import Chip from '@mui/material/Chip';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import API_PATHS from 'lib/http/apiPaths';

export default function PeoplePage() {
  return (
    <CrudResourceModule
      title="Personas"
      path={API_PATHS.people}
      columns={[
        { key: 'nombre_completo', label: 'Nombre completo' },
        { key: 'rut', label: 'RUT', render: (row) => (row.rut ? `${row.rut}-${row.rut_dv || ''}` : '-') },
        { key: 'email', label: 'Email' },
        { key: 'telefono_principal', label: 'Teléfono principal' },
        {
          key: 'activo',
          label: 'Estado',
          render: (row) => <Chip size="small" label={row.activo ? 'Activo' : 'Inactivo'} color={row.activo ? 'success' : 'default'} />
        }
      ]}
      fields={[
        { name: 'nombre_completo', label: 'Nombre completo', required: true, fullWidth: true },
        { name: 'nombres', label: 'Nombres' },
        { name: 'apellidos', label: 'Apellidos' },
        { name: 'rut', label: 'RUT (sin DV)' },
        { name: 'rut_dv', label: 'DV' },
        { name: 'email', label: 'Email', type: 'email' },
        { name: 'telefono_principal', label: 'Teléfono principal' },
        { name: 'telefono_secundario', label: 'Teléfono secundario' },
        { name: 'direccion_contacto', label: 'Dirección contacto', fullWidth: true },
        { name: 'notas', label: 'Notas', type: 'textarea', fullWidth: true },
        { name: 'activo', label: 'Activo', type: 'checkbox', defaultValue: true }
      ]}
      defaultOrdering="nombre_completo"
      searchPlaceholder="Buscar por nombre, RUT o email"
    />
  );
}
